2.16 Reusable helper functions

er_degree_table &lt;- function(n, p, max_k = n - 1) {
  tibble(
    k = 0:max_k,
    prob = dbinom(0:max_k, size = n - 1, prob = p)
  )
}

simulate_er_summary &lt;- function(n, p, reps = 100) {
  map_dfr(seq_len(reps), function(i) {
    g &lt;- sample_gnp(n = n, p = p, directed = FALSE, loops = FALSE)
    tibble(
      sim = i,
      avg_degree = mean(degree(g)),
      avg_clustering = transitivity(g, type = "average")
    )
  })
}
